sys_script_include.script:
var EQIX_Global_Products = Class.create();
EQIX_Global_Products.prototype = {
    initialize: function() {},
	hasAnyContract: function(orgId) {
        if (!orgId) {
			orgId = this._getCurrentOrgId();
        }
		var MPCPartNum = gs.getProperty('EQIX_PartNumber_MPC');
		var MPBPartNum = gs.getProperty('EQIX_MPB_POF_PART_NUM');
		var MPSPartNum = gs.getProperty('EQIX_PartNumber_MPS');
		var MPFPartNum = gs.getProperty('EQIX_MPF_POF_PART_NUM');
		var parts = [MPCPartNum, MPBPartNum, MPSPartNum, MPFPartNum];

		var gr = new GlideRecord('sn_customerservice_contract_item');
        gr.addEncodedQuery("u_siebel_asset_status=Active^u_product.u_part_numberIN" + parts.join(',') + "^account.u_org_id=" + orgId);
        gr.setLimit(1);
        gr.query();
        if (gr.next()) {
            return true;
        }
        return false;
	},
	hasAnyPermission: function(account) {
		var siCustomerPermission = new EQIX_Customer_Permissions();
		if (!account) {
			account = siCustomerPermission.getActiveAccountSysId();
		}
		var moduleMpc = 'EQIX_ManagedPrivateCloud';
		var moduleMpb = 'EQIX_ManagedPrivateBackup';
		var moduleMps = 'EQIX_ManagedPrivateStorage';
		var mpcViewable = siCustomerPermission.hasPermission('view', moduleMpc, account);
		var mpbViewable = siCustomerPermission.hasPermission('view', moduleMpb, account);
		var mpsViewable = siCustomerPermission.hasPermission('view', moduleMps, account);
		return mpcViewable || mpbViewable || mpsViewable;
	},
    hasContract: function(partNum, orgId) {
        if (!orgId) {
			orgId = this._getCurrentOrgId();
        }
        var gr = new GlideRecord('sn_customerservice_contract_item');
        gr.addEncodedQuery("u_siebel_asset_status=Active^u_product.u_part_number=" + partNum + "^account.u_org_id=" + orgId);
        gr.setLimit(1);
        gr.query();
        if (gr.next()) {
            return true;
        }
        return false;
    },
	_getCurrentOrgId: function() {
		var siCustomerPermission = new EQIX_Customer_Permissions();
		var account = siCustomerPermission.getActiveAccountSysId();
		var grAccount = new GlideRecord('customer_account');
		if (!grAccount.get(account)) {
			return false;
		}
		return grAccount.getValue('u_org_id');
	},

    type: 'EQIX_Global_Products'
};
